+    fn lint_finding_display_contains_rule_id(finding in arb_lint_finding()) {
+        let display = finding.to_string();
+        prop_assert!(display.contains(&finding.rule_id));
+        prop_assert!(display.contains(&finding.message));
+    }
+}
